import{_ as e,o as t,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F06_存貨與債務穩定度審計.md"}'),o={name:"審計報告庫/財務審計/6239_力成/20260617/F06_存貨與債務穩定度審計.md"};function i(n,a,h,s,d,c){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="f06-存貨與債務穩定度審計-財務審計專家報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務審計專家報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務審計專家報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨週轉天數252天→138天(2022-2025)，去化效率顯著提升；流動比195%仍安全，但現金比121%→69%下降，長債254億（+50%），償債壓力上升。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>存貨總額從2022年105.2億的高峰持續下降至2024年54.5億（-48.2%），2025年微升至65.7億（+20.6%），因營收擴張而補庫。存貨週轉天數改善趨勢明確：252天→210天→142天→138天，去化效率連續三年提升。現金循環從158天(2023)大幅壓縮至46天(2025)，營運資金效率優化。但流動性指標轉弱：流動比256%→195%、速動比226%→167%、現金比121%→69%。短期借款為0，無短債壓力；但長債從169億增至254億，負債比35.0%→41.9%，財務槓桿上升。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="存貨組成與去化效率" tabindex="-1">存貨組成與去化效率 <a class="header-anchor" href="#存貨組成與去化效率" aria-label="Permalink to &quot;存貨組成與去化效率&quot;">​</a></h3><p>存貨由原料構成（2025年原料58.2億、物料7.4億，無製成品/半成品），反映力成的封測業務性質——客戶來料加工、公司備原材料與物料。原料從2024年48.1億增至58.2億（+21.0%），對應2025年下半年營收擴張的備料需求。年報揭露存貨跌價損失已迴轉43.0M（2024年提列43.0M），主因庫齡久之存貨去化，無跌價風險。去化效率提升因2023-2024年調整供應鏈後，原料週轉加速。</p><h3 id="流動性壓力測試" tabindex="-1">流動性壓力測試 <a class="header-anchor" href="#流動性壓力測試" aria-label="Permalink to &quot;流動性壓力測試&quot;">​</a></h3><p>流動比195%仍在安全區間（&gt;150%），速動比167%亦充足。貨幣資金163.8億扣除無短債壓力後，營運資金需求主要來自AR增加（2025年佔用31.4億）。關鍵風險點在長債：254.1億（2024年168.9億，+50.5%），主因因應CapEx擴張（259.4億）而舉借。利息保障倍數：稅前淨利87.9億/利息支出2.59億=34倍，償息能力仍強。2026年CapEx從400億上修，長債可能進一步增加。</p><h3 id="現金循環分析" tabindex="-1">現金循環分析 <a class="header-anchor" href="#現金循環分析" aria-label="Permalink to &quot;現金循環分析&quot;">​</a></h3><p>現金循環天數從2023年158天急降至2025年46天，改善112天。拆解：DIO從210天→138天（-72天）、DPO從103天→159天（+56天）、DSO從51天→67天（+16天）。存貨效率提升及應付帳款延後付款是兩大改善動能，但DSO惡化抵消部分效益。DPO從103天拉長至159天，反映力成對供應商議價能力增強。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>負債倍數急升</strong>：長債55.5億→254.1億（+358%），兩年膨脹4.5倍。2027年折舊高峰期若營收停滯，負債比恐突破50%。</li><li><strong>現金快速下滑</strong>：現金從222.4億降至163.8億（-26.3%）。2026年CapEx 400億下，年底現金可能降至100億以下，扣除營運負債288億後淨現金可能轉負。</li><li><strong>存貨增速過快</strong>：存貨+20.6%遠超營收+2.2%，雖是補庫但需關注是否積壓過多備料。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>存貨效率顯著改善</strong>：DIO 252→138天（同業最優），現金循環158→46天，營運資金效率極佳。</li><li><strong>流動性安全邊際仍在</strong>：流動比195%、速動比167%、短債0、利息保障倍數34倍。負債/EBITDA約2.9倍仍可接受。</li><li><strong>負債用於投資成長</strong>：長債用於FOPLP/HBM/CPO先進封裝設備，非財務操作。集團負債比41.9%在半導體封測業可控。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>流動性指標轉弱主因為CapEx擴張非營運惡化。存貨效率為亮點。關鍵觀察點為2026年CapEx是否超支、2027年新產能能否量產貢獻營收。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 6239)</li><li>原始數據：FinMind TaiwanStockBalanceSheet</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 8、34-35，資產負債表及存貨附註)</li><li>年報數據：2025_Q4_6239_合併.pdf (page 12，現金流量表)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const p=e(o,[["render",i]]);export{u as __pageData,p as default};
